bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

// CUDA Kernel for bench_block logic
template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_block_kernel(Element* data, Element* sum_ptr, size_t total_elements) {
  size_t idx = blockIdx.x * static_chunk_size + threadIdx.x;
  if (idx >= total_elements) return;

  Element f = data[0];
  Element sum = 0;

  Element t = data[idx];
  for (size_t j = 0; j < compute_iterations; j++) {
    t = t * t + f;
  }
  sum += t;

  __shared__ Element shared_sum[static_chunk_size];
  shared_sum[threadIdx.x] = sum;
  __syncthreads();

  if (threadIdx.x == 0) {
    Element block_sum = 0;
    for (size_t i = 0; i < static_chunk_size; i++) {
      block_sum += shared_sum[i];
    }
    atomicAdd(sum_ptr, block_sum);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_device, Element* sum_device) {
  constexpr size_t static_chunk_size = 4096;
  size_t num_blocks = (len + static_chunk_size - 1) / static_chunk_size;

  cudaMemset(sum_device, 0, sizeof(Element));

  bench_block_kernel<Element, compute_iterations, static_chunk_size>
      <<<num_blocks, static_chunk_size>>>(src_device, sum_device, len);

  cudaDeviceSynchronize();

  Element sum_val;
  cudaMemcpy(&sum_val, sum_device, sizeof(Element), cudaMemcpyDeviceToHost);

  cudaMemcpy(src_device, &sum_val, sizeof(Element), cudaMemcpyHostToDevice);

  return len;
}

using benchmark_clock = std::chrono::steady_clock;

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);

  double* d_data;
  double* d_sum;
  cudaMalloc(&d_data, size);
  cudaMalloc(&d_sum, sizeof(double));

  auto timer_start = benchmark_clock::now();

  bench_cuda<double, 16>(num_elements, 1., -1., d_data, d_sum);

  auto timer_duration = benchmark_clock::now() - timer_start;

  cudaFree(d_data);
  cudaFree(d_sum);

  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  cudaDeviceSynchronize();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;

  auto duration = op();  
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c_host, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  float *d_float;
  double *d_double;
  int *d_int;
  float *d_sum_float;
  double *d_sum_double;
  int *d_sum_int;

  cudaMalloc(&d_float, cs.element_count<float>() * sizeof(float));
  cudaMalloc(&d_double, cs.element_count<double>() * sizeof(double));
  cudaMalloc(&d_int, cs.element_count<int>() * sizeof(int));

  cudaMalloc(&d_sum_float, sizeof(float));
  cudaMalloc(&d_sum_double, sizeof(double));
  cudaMalloc(&d_sum_int, sizeof(int));

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, d_float, d_sum_float);
    });
  });

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(cs.element_count<double>(), 1., -1., d_double, d_sum_double);
    });
  });

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(cs.element_count<int>(), 1, -1, d_int, d_sum_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;

  cudaFree(d_float);
  cudaFree(d_double);
  cudaFree(d_int);
  cudaFree(d_sum_float);
  cudaFree(d_sum_double);
  cudaFree(d_sum_int);
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

